SELECT ?person ?personLabel(YEAR(?birthDate) AS ?birthYear) WHERE {
  ?person wdt:P31 wd:Q5 .
  ?person p:P106 ?occupationStatement .
  ?occupationStatement ps:P106 wd:Q13474373 .
  FILTER NOT EXISTS {
    ?occupationStatement pq:P582 []
  }
  .
  ?person wdt:P569 ?birthDate .
  FILTER NOT EXISTS {
    ?person wdt:P570 []
  }
  .
  FILTER(datatype(?birthDate) = xsd:dateTime && YEAR(?birthDate) > 1920)
  OPTIONAL {
    ?person rdfs:label ?personLabel .
    FILTER(LANG(?personLabel) = "en")
  }
}
ORDER BY ASC(?birthDate)
LIMIT 1

SELECT ?person ?personLabel ?birthDate WHERE {
  VALUES ?occupation {
    wd:Q13474373
  }
  ?person wdt:P31 wd:Q5 ; wdt:P106 ?occupation ; wdt:P569 ?birthDate .
  FILTER NOT EXISTS {
    ?person wdt:P570 ?deathDate
  }
  ?person p:P106 ?statement .
  ?statement ps:P106 ?occupation .
  OPTIONAL {
    ?statement pq:P582 ?endDate
  }
  FILTER(! BOUND(?endDate) || ?endDate > NOW ())
  OPTIONAL {
    ?person rdfs:label ?personLabel .
    FILTER(LANG(?personLabel) = "en")
  }
}
ORDER BY ASC(?birthDate)
LIMIT 1

